#include <initializer_list>
#include <iostream>
#include <vector>

class IntArray {
    int m_size{};
    int* m_data{};
public:
    IntArray(std::initializer_list<int> list)
        : m_size{ static_cast<int>(list.size()) }
        , m_data{ new int[list.size()] } {
        int i{ 0 };
        for (int v : list)
            m_data[i++] = v;
    }
    IntArray(const int* data, int size)
        : m_size{ size }, m_data{ new int[static_cast<std::size_t>(size)] } {
        for (int i{ 0 }; i < size; ++i)
            m_data[i] = data[i];
    }
    ~IntArray() { delete[] m_data; }
    int size() const { return m_size; }
    int operator[](int index) const { return m_data[index]; }
};

void printArray(const IntArray& arr) {
    std::cout << "size: " << arr.size() << '\n';
    for (int i{ 0 }; i < arr.size(); ++i) {
        if (i > 0) std::cout << ' ';
        std::cout << arr[i];
    }
    std::cout << '\n';
}

int main() {
    int n{};
    std::cin >> n;
    std::vector<int> input(static_cast<std::size_t>(n));
    for (int i{ 0 }; i < n; ++i)
        std::cin >> input[static_cast<std::size_t>(i)];
    IntArray dynamic{ input.data(), n };
    printArray(dynamic);
    IntArray literal{ 10, 20, 30 };
    printArray(literal);
    return 0;
}

